// Driving 74HC595 Shift Register with Arduino
#define DATA_PIN 11
#define CLOCK_PIN 12
#define LATCH_PIN 8

void setup() {
  pinMode(DATA_PIN, OUTPUT);
  pinMode(CLOCK_PIN, OUTPUT);
  pinMode(LATCH_PIN, OUTPUT);
}

void loop() {
  for (int i = 0; i < 256; i++) {
    digitalWrite(LATCH_PIN, LOW);
    // Send 8 bits of data MSB First
    shiftOut(DATA_PIN, CLOCK_PIN, MSBFIRST, i);
    digitalWrite(LATCH_PIN, HIGH); // Latch data to outputs
    delay(100);
  }
}
